css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0f0a; color: white; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; }
.brand { font-size: 20px; font-weight: 800; }
.nav-links { display: flex; gap: 28px; }
.nav-links a { color: rgba(255,255,255,0.55); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-links a.active { color: #4ade80; }
.platforms { font-size: 18px; letter-spacing: 6px; }
.hero { display: flex; gap: 40px; padding: 50px 60px; align-items: center; flex-wrap: wrap; }
.hero-art { width: 220px; height: 220px; background: linear-gradient(135deg, #16a34a, #064e3b); border-radius: 24px; display: flex; align-items: center; justify-content: center; font-size: 80px; flex-shrink: 0; box-shadow: 0 30px 60px rgba(34,197,94,0.2); }
.badge { display: inline-block; background: rgba(74,222,128,0.15); color: #4ade80; font-size: 12px; font-weight: 700; letter-spacing: 0.1em; padding: 5px 14px; border-radius: 999px; margin-bottom: 16px; }
.hero-text h1 { font-size: 30px; font-weight: 800; line-height: 1.35; margin-bottom: 14px; max-width: 560px; }
.hero-text p { color: rgba(255,255,255,0.5); font-size: 14.5px; line-height: 1.7; margin-bottom: 24px; max-width: 540px; }
.player { display: flex; align-items: center; gap: 16px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 16px; padding: 14px 18px; max-width: 480px; }
.play-btn { width: 44px; height: 44px; border-radius: 50%; background: linear-gradient(135deg, #4ade80, #16a34a); border: none; color: #052e16; font-size: 16px; cursor: pointer; flex-shrink: 0; }
.player-info { flex: 1; }
.track-bar { height: 6px; background: rgba(255,255,255,0.08); border-radius: 999px; overflow: hidden; margin-bottom: 6px; }
.track-fill { height: 100%; width: 0%; background: linear-gradient(90deg, #4ade80, #16a34a); border-radius: 999px; transition: 1s linear; }
.time { display: flex; justify-content: space-between; font-size: 11.5px; color: rgba(255,255,255,0.4); font-weight: 600; }
.speed { font-size: 12px; color: rgba(255,255,255,0.5); font-weight: 700; background: rgba(255,255,255,0.06); padding: 6px 10px; border-radius: 8px; }
.episodes { padding: 20px 60px 50px; }
.episodes h2 { font-size: 26px; font-weight: 800; margin-bottom: 22px; }
.episode-list { display: flex; flex-direction: column; gap: 10px; }
.episode { display: flex; align-items: center; gap: 18px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.06); border-radius: 14px; padding: 16px 18px; cursor: pointer; transition: 0.15s; }
.episode:hover, .episode.selected { background: rgba(74,222,128,0.07); border-color: rgba(74,222,128,0.25); }
.ep-num { font-size: 22px; font-weight: 900; color: rgba(255,255,255,0.15); width: 36px; flex-shrink: 0; }
.ep-info { flex: 1; }
.ep-info h3 { font-size: 15px; font-weight: 700; margin-bottom: 4px; }
.ep-meta { font-size: 12px; color: rgba(255,255,255,0.4); }
.ep-play { width: 36px; height: 36px; border-radius: 50%; background: rgba(255,255,255,0.06); border: none; color: white; font-size: 12px; cursor: pointer; flex-shrink: 0; }
.subscribe { text-align: center; padding: 60px; background: linear-gradient(135deg, rgba(74,222,128,0.08), transparent); }
.subscribe h2 { font-size: 28px; font-weight: 800; margin-bottom: 10px; }
.subscribe p { color: rgba(255,255,255,0.5); font-size: 14px; margin-bottom: 26px; }
.platform-buttons { display: flex; gap: 12px; justify-content: center; flex-wrap: wrap; }
.platform-buttons button { background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.12); color: white; padding: 13px 24px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
@media (max-width: 900px) { .hero, .episodes, .subscribe { padding: 40px 24px; } .nav-links { display: none; } .hero-text h1 { font-size: 22px; } }

