let playing = false;
let progressTimer = null;
let progress = 0;

function togglePlay(btn) {
  playing = !playing;
  btn.textContent = playing ? '❚❚' : '▶';
  if (playing) {
    progressTimer = setInterval(() => {
      progress = Math.min(progress + 0.5, 100);
      document.getElementById('trackFill').style.width = progress + '%';
      const totalSeconds = Math.floor((progress / 100) * (48 * 60 + 12));
      const m = String(Math.floor(totalSeconds / 60)).padStart(2, '0');
      const s = String(totalSeconds % 60).padStart(2, '0');
      document.getElementById('current').textContent = `${m}:${s}`;
      if (progress >= 100) clearInterval(progressTimer);
    }, 500);
  } else {
    clearInterval(progressTimer);
  }
}

function selectEpisode(el) {
  document.querySelectorAll('.episode').forEach(e => e.classList.remove('selected'));
  el.classList.add('selected');
}
